// In TelegramChannel class
private normalizeForTelegramHtml(text: string): string {
  // 1) if already HTML-like (trusted tags), return text
  // 2) else escape text and convert markdown tokens to Telegram-safe HTML
}

async sendMessage(chatId: number, text: string): Promise<void> {
  const chunks = this.splitMessage(text, 4000);
  for (const chunk of chunks) {
    const formatted = this.normalizeForTelegramHtml(chunk);
    await this.apiCall('sendMessage', {
      chat_id: chatId,
      text: formatted,
      parse_mode: 'HTML',
    }).catch(async () => {
      // existing fallback remains
    });
  }
}
